+        }
+    });
+    let offset_proxy = if query.cursor.is_none() {
+        #[allow(clippy::cast_possible_truncation)]
+        {
+            scope_discriminator as usize
+        }
+    } else {
+        offset_proxy
+    };
+
+    QueryCacheKey::new(
+        &query.text,
+        mode,
+        &filter,
+        cache_epoch,
+        offset_proxy,
+        query.effective_limit(),
+    )
